#!/usr/bin/env node

const fs = require("fs-extra");
const path = require("path");

const { criarProjeto, criarRecurso, listarModels } = require("./functions");
const { gerarInsomnia } = require("./functions-insomnia");

const args = process.argv.slice(2);

if (args[0] === "-r") {
  criarRecurso(args[1]);
} else if (args[0] === "-models") {
  let modelos = listarModels();

  modelos.forEach((modelo) => {
    criarRecurso(modelo.toLowerCase());
  });
} else if (args[0] === "-insomnia") {
  gerarInsomnia();
} else {
  criarProjeto(args[0]);
}
